VALUES
  ('colonel-d0d1b9a2-moex-00008', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司使用間接法來編製現金流量表。甲公司X4年相關資料如下：購買1 台機器付款$170,000，支付現金股利給股東$50,000，權益法認列投資收益 $75,000，採權益法之長期股權投資收到股利$60,000，簽發票據$105,000取 得 1 筆土地，發行公司債$280,000。X4 年度折舊費用$25,000。X4 年度應 收帳款淨額增加$30,000，存貨減少$25,000，應付帳款減少$26,000。X4年 度淨利$100,000，期初現金餘額$50,000。甲公司X4年的期末現金餘額為：', '["$189,000", "$239,000", "$249,000", "$339,000 30650"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00009', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X2 年相關資料如下：①稅前淨利$500,000，稅率 20%。②普通股', '["X2年12月31日發 放40%股票股利。甲公司X2年基本每股盈餘為：", "$1.43", "$1.79", "$2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00010', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司與丁公司於X4年1月1日簽訂1年期合約，該合約明定甲公司每 月提供辦公室清潔服務6次給丁公司，而丁公司則於每月月底以其普通股 500 股作為取得甲公司服務之對價。丁公司普通股每股公允價值於 X4 年', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00011', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '月 1 日為$15；丁公司普通股於 X4 年 1 月、2 月、3 月底之每股公允價 值分別為$14、$16、$18。甲公司於X4年第一季因該合約而認列之勞務收 入為：', '["$21,000", "$22,500", "$24,000", "$27,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00012', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司向丁租賃公司承租1台機器設備，合約的內容符合融資租賃。甲公司在 6年的租期中，每年年初須支付租金$110,000，該租金包含每年機器設備的維修 、保險與稅金$20,000。甲公司為取得該租賃發生的原始直接成本為$7,000。承 租人的增額借款利率為 10%，出租人的隱含利率為 8%，甲公司得知隱含利率 。甲公司應認列使用權資產的金額為：（P =3.79079，P =3.99271） 5,10% 5,8%', '["$359,344", "$366,344", "$456,344", "$556,198"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00013', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', 'X2年1月1日，甲公司給18位經理每人8,000單位認股權，每單位認股 權得以$60 認購公司普通股 1 股，當時每股普通股的面額為$10，市價為 $82，每單位認股權的公允價值則為$20。每位經理必須在公司內服務滿 4 年，第5年開始得行使認股權。經理如果自得行使日起2年內未行使，其 所持有的認股權就失效。X5 年 7 月 1 日，甲公司有 4 位經理因故離職， X6 年 1 月 1 日則有 9 位經理行使認股權，一直到 X8 年 1 月 1 日都沒有 經理行使認股權。甲公司X5年應認列的酬勞成本為：', '["$72,000", "$80,000", "$88,000", "$168,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00014', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '乙公司於X6年初保留盈餘帳戶餘額為$450,000，X6年相關資料如下：淨 利$1,200,000，現金股利$250,000，庫藏股再發行價格超過成本$100,000， 提撥或有損失準備$250,000，股票股利$150,000。乙公司X6年12月31日 保留盈餘應有的餘額為：', '["$1,000,000", "$1,100,000", "$1,250,000", "$1,400,000 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00015', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '丙公司，X9年12月31日，股本帳戶情況如下： 普通股股本（面額$10） $900,000 5%非累積非參加特別股股本（面額$100） 240,000 8%累積完全參加特別股股本（面額$100） 1,600,000 丙公司於 X5 年 1 月 1 日成立，至 X8 年底止，尚未發放過任何股利。X9 年度丙公司宣告發放股利$764,000。下列關於丙公司 X9 年度之敘述何者 正確？', '["普通股應分配的股利為$86,400", "5%特別股應分配的股利為$15,504", "8%特別股應分配的股利為$640,000", "8%特別股應分配的股利為$663,358"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00016', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '丙公司X1 年銷售1 種附有2 年保證維修期限之玩具狗，依據公司過去經 驗得知有 55%玩具狗不會發生損壞，30%玩具狗會發生小瑕疵，15%玩具 狗則會發生重大瑕疵。每隻玩具狗發生小瑕疵和重大瑕疵時之平均修理費 用分別為$180及$450。丙公司X1年度共銷售200隻玩具狗，每隻售價為 $2,500，X1 年實際發生的免費維修支出$8,500。丙公司X1 年12 月31日 估計產品保證負債餘額為：', '["$0", "$8,500", "$15,800", "$24,300"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00017', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司X9年度淨利$35,000，部分資產負債表帳戶資料如下： 部分資產負債表帳戶 X9年12月31日 X8年12月31日 應付現金股利 $17,000 $24,000 普通股股本（面額$10） 100,000 90,000 保留盈餘 140,000 120,000 資本公積 25,000 15,000 甲公司X9年支付現金股利金額為：', '["$7,000", "$15,000", "$22,000", "$42,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL)
